module sample_rate_converter (
    input clk,
    input reset,
    input [7:0] in_sample,
    output reg [7:0] out_sample
);
    reg [1:0] obf_count;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            out_sample <= 8'b0;
            obf_count <= 2'b0;
        end else begin
            if (obf_count == 2'b11) begin
                out_sample <= in_sample;
                obf_count <= 2'b0;
            end else begin
                obf_count <= obf_count + 1;
            end
        end
    end
endmodule
